package Day7;

import java.util.HashSet;
import java.util.Set;

public class HashSetEx {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Set <String> s= new HashSet();
		s.add("Java");
		s.add("Java");
		s.add(null);
		s.add(null);
		s.add("cucumber");
		
		System.out.println(s);

	}

}
